class GameState(Enum):
    WAITING = "waiting"
    IN_PROGRESS = "in_progress"
    FINISHED = "finished"
    PAUSED = "paused"


@dataclass
class Player:
    player_id: str
    name: str
    score: int = 0
    ping: int = 0
    team: str = ""
    connected_at: float = 0.0

    def to_safe_dict(self) -> dict:
        """Return only publicly safe information about the player."""
        return {
            "name": self._sanitize_name(self.name),
            "score": self.score,
            "ping": self.ping,
            "team": self.team,
        }

    @staticmethod
    def _sanitize_name(name: str) -> str:
        """Sanitize player name to prevent injection attacks."""
        # Allow only printable ASCII, limit length
        sanitized = ''.join(c for c in name if 32 <= ord(c) < 127)
        return sanitized[:32]


