class RateLimiter:
    """Token bucket rate limiter per IP address."""

    def __init__(self, max_tokens: int = 10, refill_rate: float = 2.0,
                 cleanup_interval: float = 60.0):
        self.max_tokens = max_tokens
        self.refill_rate = refill_rate  # tokens per second
        self.cleanup_interval = cleanup_interval
        self._buckets: Dict[str, dict] = {}
        self._lock = threading.Lock()
        self._last_cleanup = time.monotonic()

    def allow(self, ip: str) -> bool:
        now = time.monotonic()
        with self._lock:
            self._maybe_cleanup(now)

            if ip not in self._buckets:
                self._buckets[ip] = {
                    "tokens": self.max_tokens - 1,
                    "last_refill": now
                }
                return True

            bucket = self._buckets[ip]
            elapsed = now - bucket["last_refill"]
            bucket["tokens"] = min(
                self.max_tokens,
                bucket["tokens"] + elapsed * self.refill_rate
            )
            bucket["last_refill"] = now

            if bucket["tokens"] >= 1:
                bucket["tokens"] -= 1
                return True
            return False

    def _maybe_cleanup(self, now: float):
        if now - self._last_cleanup > self.cleanup_interval:
            stale = [
                ip for ip, b in self._buckets.items()
                if now - b["last_refill"] > self.cleanup_interval
            ]
            for ip in stale:
                del self._buckets[ip]
            self._last_cleanup = now


class FragmentedResponseSender:
    """Handles sending large responses as fragmented UDP packets."""

    # Conservative max payload to stay well under typical MTU
    MAX_FRAGMENT_PAYLOAD = 1200
    # Header: 4 bytes magic + 16 bytes request_id + 2 bytes fragment_index +
    #         2 bytes total_fragments + 4 bytes total_size
    HEADER_SIZE = 28
    MAGIC = b'\x47\x53\x52\x46'  # "GSRF" - Game Server Response Fragment

    @staticmethod
    def send_response(sock: socket.socket, addr: tuple, data: bytes,
                      request_id: bytes):
        """Fragment and send a large response."""
        max_payload = FragmentedResponseSender.MAX_FRAGMENT_PAYLOAD
        total_size = len(data)
        total_fragments = (total_size + max_payload - 1) // max_payload

        if total_fragments > 65535:
            logger.warning(
                "Response too large to fragment (%d bytes), truncating",
                total_size
            )
            data = data[:max_payload * 65535]
            total_size = len(data)
            total_fragments = 65535

        for i in range(total_fragments):
            offset = i * max_payload
            chunk = data[offset:offset + max_payload]

            header = (
                FragmentedResponseSender.MAGIC +
                request_id[:16].ljust(16, b'\x00') +
                struct.pack('!HHI', i, total_fragments, total_size)
            )

            packet = header + chunk
            try:
                sock.sendto(packet, addr)
            except OSError as e:
                logger.error("Failed to send fragment %d to %s: %s",
                             i, addr, e)
                break


class GameServer:
    """UDP Game Server that responds to status queries."""

    # Protocol constants
    QUERY_MAGIC = b'\x47\x53\x51\x00'  # "GSQ\0" - Game Server Query
    RESPONSE_MAGIC = b'\x47\x53\x52\x00'  # "GSR\0" - Game Server Response

    # Query types
    QUERY_STATUS = 0x01
    QUERY_PLAYERS = 0x02
    QUERY_RULES = 0x03
    QUERY_PING = 0x04

    # Limits
    MAX_PACKET_SIZE = 2048  # Max incoming packet size
    MAX_RESPONSE_SIZE = 65536  # Max total response size before truncation

    def __init__(self, host: str = "0.0.0.0", port: int = 27015,
                 server_info: Optional[ServerInfo] = None):
        # Validate host and port
        self._validate_bind_address(host, port)

        self.host = host
        self.port = port
        self.server_info = server_info or ServerInfo()
        self.players: Dict[str, Player] = {}
        self._players_lock = threading.Lock()
        self._running = False
        self._socket: Optional[socket.socket] = None
        self._rate_limiter = RateLimiter(max_tokens=10, refill_rate=2.0)
        self._challenge_tokens: Dict[str, dict] = {}
        self._challenge_lock = threading.Lock()
        self._challenge_secret = secrets.token_bytes(32)

        # Blocked IP ranges (private by default are allowed for LAN,
        # but you can add specific blocked IPs)
        self._blocked_ips: set = set()

    @staticmethod
    def _validate_bind_address(host: str, port: int):
        """Validate the bind address and port."""
        try:
            ipaddress.ip_address(host)
        except ValueError:
            if host != "0.0.0.0" and host != "::":
                raise ValueError(f"Invalid bind address: {host}")

        if not (1 <= port <= 65535):
            raise ValueError(f"Invalid port number: {port}")

    def block_ip(self, ip: str):
        """Block an IP address from querying."""
        try:
            ipaddress.ip_address(ip)
            self._blocked_ips.add(ip)
            logger.info("Blocked IP: %s", ip)
        except ValueError:
            logger.warning("Invalid IP address to block: %s", ip)

    def _is_ip_blocked(self, ip: str) -> bool:
        return ip in self._blocked_ips

    def add_player(self, player: Player):
        """Add a player to the server (thread-safe)."""
        with self._players_lock:
            if len(self.players) >= self.server_info.max_players:
                logger.warning("Cannot add player, server is full")
                return False
            # Sanitize player name on add
            player.name = Player._sanitize_name(player.name)
            player.connected_at = time.time()
            self.players[player.player_id] = player
            logger.info("Player added: %s", player.name)
            return True

    def remove_player(self, player_id: str):
        """Remove a player from the server (thread-safe)."""
        with self._players_lock:
            if player_id in self.players:
                name = self.players[player_id].name
                del self.players[player_id]
                logger.info("Player removed: %s", name)

    def _generate_challenge(self, addr: tuple) -> bytes:
        """Generate a challenge token for an address."""
        timestamp = int(time.monotonic())
        addr_key = f"{addr[0]}:{addr[1]}:{timestamp // 30}"
        mac = hmac.new(
            self._challenge_secret,
            addr_key.encode('utf-8'),
            hashlib.sha256
        ).digest()[:8]
        return mac

    def _verify_challenge(self, addr: tuple, token: bytes) -> bool:
        """Verify a challenge token, checking current and previous window."""
        timestamp = int(time.monotonic())
        for window_offset in [0, -1]:
            addr_key = f"{addr[0]}:{addr[1]}:{timestamp // 30 + window_offset}"
            expected = hmac.new(
                self._challenge_secret,
                addr_key.encode('utf-8'),
                hashlib.sha256
            ).digest()[:8]
            if hmac.compare_digest(token, expected):
                return True
        return False

    def _handle_query(self, data: bytes, addr: tuple) -> Optional[bytes]:
        """Parse and handle an incoming query packet."""
        client_ip = addr[0]

        # Check if IP is blocked
        if self._is_ip_blocked(client_ip):
            logger.debug("Blocked query from %s", client_ip)
            return None

        # Rate limiting
        if not self._rate_limiter.allow(client_ip):
            logger.warning("Rate limited query from %s", client_ip)
            return None

        # Validate minimum packet size: 4 magic + 1 query_type + 16 request_id
        if len(data) < 21:
            logger.debug("Packet too small from %s (%d bytes)",
                         client_ip, len(data))
            return None

        # Validate magic bytes
        if data[:4] != self.QUERY_MAGIC:
            logger.debug("Invalid magic from %s", client_ip)
            return None

        query_type = data[4]
        request_id = data[5:21]

        # For status/player queries, require challenge-response
        if query_type in (self.QUERY_STATUS, self.QUERY_PLAYERS,
                          self.QUERY_RULES):
            if len(data) >= 29:
                # Client provided a challenge token
                challenge_token = data[21:29]
                if not self._verify_challenge(addr, challenge_token):
                    logger.debug("Invalid challenge from %s", client_ip)
                    # Send new challenge
                    return self._build_challenge_response(request_id, addr)
            else:
                # No challenge token, send challenge
                return self._build_challenge_response(request_id, addr)

        if query_type == self.QUERY_STATUS:
            return self._build_status_response(request_id)
        elif query_type == self.QUERY_PLAYERS:
            return self._build_players_response(request_id)
        elif query_type == self.QUERY_RULES:
            return self._build_rules_response(request_id)
        elif query_type == self.QUERY_PING:
            return self._build_ping_response(request_id)
        else:
            logger.debug("Unknown query type 0x%02x from %s",
                         query_type, client_ip)
            return None

    def _build_challenge_response(self, request_id: bytes,
                                  addr: tuple) -> bytes:
        """Build a challenge response packet."""
        challenge = self._generate_challenge(addr)
        response = {
            "type": "challenge",
            "challenge": challenge.hex()
        }
        payload = json.dumps(response, separators=(',', ':')).encode('utf-8')
        return self.RESPONSE_MAGIC + request_id + b'\x00' + payload

    def _build_status_response(self, request_id: bytes) -> bytes:
        """Build a full status response with server info and player list."""
        with self._players_lock:
            player_list = [p.to_safe_dict() for p in self.players.values()]
            player_count = len(self.players)

        status = {
            "type": "status",
            "server": {
                "name": self.server_info.server_name[:64],
                "map": self.server_info.map_name[:32],
                "game_mode": self.server_info.game_mode[:32],
                "players": player_count,
                "max_players": self.server_info.max_players,
                "state": self.server_info.game_state.value,
                "version": self.server_info.version[:16],
            },
            "players": player_list,
            "timestamp": int(time.time()),
        }

        payload = json.dumps(status, separators=(',', ':')).encode('utf-8')

        # Truncate if too large
        if len(payload) > self.MAX_RESPONSE_SIZE:
            # Send server info without full player list
            status["players"] = []
            status["players_truncated"] = True
            payload = json.dumps(status, separators=(',', ':')).encode('utf-8')

        return self.RESPONSE_MAGIC + request_id + b'\x01' + payload

    def _build_players_response(self, request_id: bytes) -> bytes:
        """Build a player list response."""
        with self._players_lock:
            player_list = [p.to_safe_dict() for p in self.players.values()]

        response = {
            "type": "players",
            "players": player_list,
            "count": len(player_list),
            "timestamp": int(time.time()),
        }

        payload = json.dumps(response, separators=(',', ':')).encode('utf-8')

        if len(payload) > self.MAX_RESPONSE_SIZE:
            response["players"] = player_list[:self.server_info.max_players // 2]
            response["truncated"] = True
            response["count"] = len(response["players"])
            payload = json.dumps(response, separators=(',', ':')).encode('utf-8')

        return self.RESPONSE_MAGIC + request_id + b'\x02' + payload

    def _build_rules_response(self, request_id: bytes) -> bytes:
        """Build a server rules/settings response."""
        rules = {
            "type": "rules",
            "rules": {
                "max_players": self.server_info.max_players,
                "game_mode": self.server_info.game_mode,
                "map": self.server_info.map_name,
                "version": self.server_info.version,
            },
            "timestamp": int(time.time()),
        }

        payload = json.dumps(rules, separators=(',', ':')).encode('utf-8')
        return self.RESPONSE_MAGIC + request_id + b'\x03' + payload

    def _build_ping_response(self, request_id: bytes) -> bytes:
        """Build a simple ping response (no challenge required)."""
        response = {
            "type": "pong",
            "timestamp": int(time.time()),
        }
        payload = json.dumps(response, separators=(',', ':')).encode('utf-8')
        return self.RESPONSE_MAGIC + request_id + b'\x04' + payload

    def _send_response(self, response: bytes, addr: tuple):
        """Send a response, fragmenting if necessary."""
        if self._socket is None:
            return

        # Extract request_id from response for fragment headers
        request_id = response[4:20]

        if len(response) <= FragmentedResponseSender.MAX_FRAGMENT_PAYLOAD + \
                FragmentedResponseSender.HEADER_SIZE:
            # Small enough to send in one packet
            try:
                self._socket.sendto(response, addr)
            except OSError as e:
                logger.error("Failed to send response to %s: %s", addr, e)
        else:
            # Need to fragment
            FragmentedResponseSender.send_response(
                self._socket, addr, response, request_id
            )

    def start(self):
        """Start the game server."""
        self._socket = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self._socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)

        # Set socket timeout so we can check _running flag periodically
        self._socket.settimeout(1.0)

        try:
            self._socket.bind((self.host, self.port))
        except OSError as e:
            logger.error("Failed to bind to %s:%d: %s",
                         self.host, self.port, e)
            self._socket.close()
            self._socket = None
            raise

        self._running = True
        logger.info("Game server started on %s:%d", self.host, self.port)

        try:
            while self._running:
                try:
                    data, addr = self._socket.recvfrom(self.MAX_PACKET_SIZE)
                except socket.timeout:
                    continue
                except OSError as e:
                    if self._running:
                        logger.error("Socket error: %s", e)
                    break

                # Process query in a try block to prevent crashes
                try:
                    response = self._handle_query(data, addr)
                    if response is not None:
                        self._send_response(response, addr)
                except Exception as e:
                    logger.error("Error handling query from %s: %s",
                                 addr, e, exc_info=True)
        finally:
            self.stop()

    def stop(self):
        """Stop the game server."""
        self._running = False
        if self._socket:
            try:
                self._socket.close()
            except OSError:
                pass
            self._socket = None
            logger.info("Game server stopped")


